var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그, 그만!","JPN":"ちょ、ちょっと！","ENG":"S-stop!","TWN":"等…等一下！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"더는 못 뛰어. 심장이 목구멍으로 튀어나올 것 같아.","JPN":"もう走れない。口から心臓が飛び出そう。","ENG":"I can’t... I feel like I’m about to cough up a lung...!","TWN":"我跑不動了啦！心臟好像快跳出來了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하아아.","JPN":"はああ。","ENG":"*Huff.*","TWN":"呼呼呼…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너 때문에 대체 이게 무슨 꼴이야!","JPN":"アンタのせいでなんてザマなの！","ENG":"Just look at the mess you got me into!","TWN":"你看你把我害成什麼樣子！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"멀쩡히 야근하던 사람 휘말리게 한 것도 모자라서 하마터면 죽을 뻔했잖아!","JPN":"まともに残業してた人を巻き込んで、しかも危うく死ぬところだったじゃん！","ENG":"You're the reason I almost died over there while doing nothing but paperwork!","TWN":"我在加班你把我拖下水不打緊，還害我差點喪命！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"총알에 스치기라도 했으면 나 같은 건 즉사야, 즉사!","JPN":"銃弾がかすりでもしたら私なんか即死だよ、即死！","ENG":"One bullet grazes and I’d be instantly dead! You hear me?!","TWN":"要是被子彈掃到，像我這種人根本必死無疑好嗎！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……미안.","JPN":"……ごめん。","ENG":"...Sorry.","TWN":"……對不起。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"수배범 얘기는 또 뭐야? 범죄자라도 돼? 소녀 스파이, 뭐 그런 거?","JPN":"それに手配犯って何？　犯罪者なの？　少女スパイ、とか？","ENG":"And what’s up with you being a fugitive anyway? Are you a criminal? Or perhaps a child spy?","TWN":"通緝犯是怎麼回事？你犯法嗎？還是你是少女特務？是嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"그런 건 아니야.","JPN":"そんなのじゃないよ。","ENG":"It’s nothing like that.","TWN":"不是的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"꼭 해야 하는 일이 있어서…….","JPN":"どうしてもやらなければならないことがあって……","ENG":"There’s just something that I have to do...","TWN":"因為我有必須要做的事……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"관심 없고, 어쨌든 위저드 애는 아니라는 거잖아? 그런 줄도 모르고 널 감싸기나 하고……","JPN":"興味ないし、とにかくウィザードの子じゃないってことでしょ？　そうとも知らずアンタを庇うなんて……","ENG":"Whatever. So you’re not a part of Wizard, right? If I had only known that earlier...","TWN":"我不想聽，而且你根本不是魔法師的人，我還傻傻地想袒護你……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"지원팀에서 충분히 오해할 만했지. 멍청한 글린다…….","JPN":"どうりで応援班が誤解するわけだよ。間抜けグリンダ……","ENG":"Stupid Glinda... No wonder the support team mistook me as an accomplice...","TWN":"支援組肯定會誤會的啦！我這個白癡……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이제 어떡하냐고. <color=#ffd34c>헤이븐 랜드</color>는커녕 돌아갈 곳도 없어졌어…….","JPN":"どうしたらいいんだよ。<color=#ffd34c>ヘイブンランド</color>どころか、帰るところさえなくなったじゃん……","ENG":"Now what am I supposed to do? I can’t go back to <color=#ffd34c>Havenland</color> or anywhere in fact...","TWN":"你說現在要怎麼辦？還妄想上什麼<color=#ffd34c>天堂樂園</color>，現在根本無家可歸……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……미안해.","JPN":"……ごめんね。","ENG":"...Sorry.","TWN":"……對不起。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"미안한 줄 알긴 알아?","JPN":"本当に申し訳ないと思ってるの？","ENG":"Is that all you have to say?","TWN":"你還知道要說對不起嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……뭐, 됐다. 네가 미안해한다고 어디 취직시켜 줄 것도 아니고.","JPN":"……まあ、いいわ。アンタが謝ったってどっか就職させてくれるわけでもないし。","ENG":"Forget it. It’s not like you saying sorry is going to get me a job.","TWN":"……算了，就算你道歉，我也不會因此找到新工作。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이미 단단히 오해한 이상 널 갖다 바친다고 날 멀쩡히 살려줄 것도 아닌데.","JPN":"すでに誤解されている以上、アンタを連れて帰っても私を無事生かしてくれるわけもない。","ENG":"They must’ve already branded me as a traitor, so going back with you is not an option.","TWN":"而且他們都已經認定我跟你是一夥的了，就算我把你交給他們，他們也不會因此放過我的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"피곤하다, 피곤해…….","JPN":"ああ、疲れた……","ENG":"Geez... I’m exhausted...","TWN":"我累了，好累……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"야.","JPN":"ねえ。","ENG":"Hey.","TWN":"喂！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜 따라와?","JPN":"なんでついてくるの？","ENG":"Why are you following me?","TWN":"跟著我幹嘛？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이제 네 갈 길 가. 이 정도 괴롭혔으면 됐잖아?","JPN":"もう行きたいところに行きなよ。迷惑かけるのもいい加減にしてさ？","ENG":"Don’t you think you’ve done enough damage? Go do your thing and leave me out of it.","TWN":"你把我搞到這麼慘還不夠嗎？還不走開？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"미안…….","JPN":"ごめん……","ENG":"...Sorry.","TWN":"對不起……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"또 사과하네. 별로 듣기도 싫은 거.","JPN":"また謝る。別に聞きたくもないのに。","ENG":"Again with the apologizing...! It’s starting to get annoying, you know.","TWN":"又道歉，我不想聽啦！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"됐으니까 그만 헤어지자고. 더 너랑 얽히기 싫어.","JPN":"いいからもう別れようって。これ以上アンタと関わりたくないから。","ENG":"I think this is where we part ways. I don't want anything to do with you anymore.","TWN":"就這樣吧，現在起我們各走各的，我不想再跟你有什麼牽扯！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……오늘 밤만 같이 있으면 안 될까?","JPN":"……今夜だけ一緒にいるのはダメ？","ENG":"Can I stay with you just for the night?","TWN":"……今晚可以跟你一起嗎？今晚就好？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"오늘 밤만? 내가 굳이 왜?","JPN":"今夜だけ？　なんで私が？","ENG":"\\"Just for the night?\\" But why would I want that?","TWN":"今晚就好？為什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"아… 악몽을…….","JPN":"あ……悪夢を……","ENG":"Oh... The nightmare─","TWN":"惡…惡夢……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아아. 너도 악몽을 꾸긴 하나 보네.","JPN":"ああ。アンタも悪夢を見るんだね。","ENG":"Oh, is it because you have nightmares?","TWN":"喔喔，你也會做惡夢是吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래서 무서워서, 같이 자달라는 거야?","JPN":"それで、怖いから一緒に寝てほしいってこと？","ENG":"So you’re scared to sleep alone?","TWN":"你怕做惡夢，所以想要我陪你睡是嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……응. 맞아. 그런 거야.","JPN":"……うん。そう。そういうこと。","ENG":"…Yes. That’s it.","TWN":"……嗯，對，就是這樣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……정말 귀찮은 애네. 성가셔.","JPN":"……本当面倒くさい子ね。鬱陶しい。","ENG":"Ugh... You really are a handful.","TWN":"……嘖嘖，真是麻煩的丫頭！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"난 여기서 잘 거야. 길거리에서 자는 거 싫으면 당장 네 갈 길 가고.","JPN":"私はここで寝る。路上で寝たくないなら、今すぐ行っちゃって。","ENG":"I’m going to sleep here. If you don’t like sleeping out on the street, then I suggest you find another place to sleep.","TWN":"我要睡在這裡，你不想睡大街上的話，就快走開吧！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"길거리에서 잔다고?","JPN":"路上で寝るの？","ENG":"You’re gonna sleep on the streets?","TWN":"睡大街上？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 어디, 갈 곳이라도 있어? 있으면 나 좀 데려가던가.","JPN":"じゃあ、どっか行くところでもある？　あるなら私も連れてってよ。","ENG":"Then where else can I go? If you know a place, lead the way.","TWN":"不然呢？還有地方可以去嗎？有的話帶上我？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"그런 건 없지만…….","JPN":"そんなところはないんだけど……","ENG":"No... I don’t...","TWN":"是沒有……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"대책 없네. 그럼 지금까지 잠은 어디서 잔 거야?","JPN":"あきれた。それじゃ今までどこで寝てたの？","ENG":"Ugh... I can’t believe this. Then where did you sleep all this time?","TWN":"結果你也沒有，那你之前都睡哪？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"잠은……","JPN":"寝るのは……","ENG":"I...","TWN":"睡……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니. 됐다. 별로 궁금하지도 않아.","JPN":"いや。いいよ。別に知りたくもない。","ENG":"Forget it. I’m not curious one bit.","TWN":"不用回答我，我不想知道。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어디 보자. 여기면 사람도 거의 안 다닐 것 같고, 적당히 쓰레기도 좀 버려져 있고…….","JPN":"どれどれ。ここだったら人も通らなさそうだし、適当にゴミも捨てられてるし……","ENG":"Lemme see... Right here seems good. There isn't much foot traffic and there isn't much trash lying around...","TWN":"我看看，這裡沒什麼人會經過，垃圾也還好……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"야. 네 발 옆에 상자나 좀 주워 줘.","JPN":"ねぇ。アンタの足元にある箱、ちょっと拾って。","ENG":"Hey, bring that cardboard box next to you.","TWN":"喂，把你腳邊的紙箱拿來給我。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"여기.","JPN":"はい。","ENG":"Here.","TWN":"給你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"오~ 꽤 튼튼한데. 바람 정도는 막아주겠네.","JPN":"お～結構丈夫じゃん。風くらいは防げそうだね。","ENG":"Ooh! This looks sturdy. It’ll block out the harsh winds.","TWN":"喔～滿厚實的欸，應該可以拿來擋風。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"야, 너. 와서 여기 잡고 있어. 바람에 안 날리게 조심하고.","JPN":"ちょっと、アンタ。ここ掴んでてよ。風に飛ばされないように気をつけて。","ENG":"Hey, you. Come here and hold this up. Be careful not to lose it to the wind.","TWN":"喂，你過來睡這裡，小心不要弄到紙箱！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"응. 알겠어.","JPN":"うん。わかった。","ENG":"Okay. I’ll try.","TWN":"嗯，好。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그…… 하아. 야.","JPN":"その……はあ。ねえ。","ENG":"Um... *Sigh...* Hey.","TWN":"那個……喂！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이름.","JPN":"名前。","ENG":"Name.","TWN":"名字。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"답답하게 구네. 계속 야, 라고 부를 순 없잖아?","JPN":"じれったいなあ。ずっと「ねえ」って呼ぶわけにもいかないじゃん？","ENG":"Ugh… I can’t keep calling you \\"hey\\", right?","TWN":"真是的，總不能一直叫你喂吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"먼저 이름 말하는 게 예의라고 할 생각이면 그만 둬. 이쪽은 말해줄 생각 없으니까.","JPN":"先に名乗るのが礼儀だとか言うつもりならやめときな。こっちは言う気ないから。","ENG":"If you're going to say it's courteous to first tell you my name, forget it. I'm not going to tell you anything.","TWN":"你該不會認為問別人名字之前，要先說自己的名字才是有禮貌的吧？勸你打消這個念頭，我沒打算告訴你我的名字。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"알겠어, 글린다.","JPN":"わかった。グリンダ。","ENG":"Okay, Glinda.","TWN":"好的，格琳達。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아까 내가 얘기했구나.","JPN":"さっき私が言ったんだった。","ENG":"Oh right. I already said my name out loud.","TWN":"對吼，我剛有提到我的名字。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"으응…….","JPN":"うん……","ENG":"Yes…","TWN":"嗯嗯……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"두 번 정도…….","JPN":"2回くらい……","ENG":"Twice...","TWN":"提到二次……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"나…… 이름에 대해 생각해 본 적이 없어.","JPN":"私……名前について考えてみたことない。","ENG":"I... haven’t thought about what my name is.","TWN":"我……對名字沒什麼想法。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"엥? 이건 또 무슨 소리?","JPN":"は？　どういうこと？","ENG":"Huh? What’s that supposed to mean?","TWN":"蛤？這什麼意思？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"누군가 날 불러줄 일이 없어서……. 이름은 그럴 때 필요한 거잖아?","JPN":"誰かが私を呼んでくれることがなかったから……名前ってそういう時に必要なんでしょう？","ENG":"I don’t need a name... when there’s no one to call me, right?","TWN":"因為沒有人會喊我……要有人喊你才會需要名字吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……상당히 귀찮은 애랑 엮여 버렸네.","JPN":"……相当面倒な子と関わっちゃったな。","ENG":"Ugh... What did I do to get stuck with this annoying kid?","TWN":"……看來我招惹到一個麻煩人物。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"사연 같은 건 아무래도 좋으니까…… 아까 내가 뭐라고 불렀더라? <color=#ffd34c>루루</color>?","JPN":"事情なんかどうでもいいからさ……さっきなんて呼んだっけ？　<color=#ffd34c>ルル</color>？","ENG":"I don’t care about your little sob story. But what did I call you before? <color=#ffd34c>Lulu</color>, was it?","TWN":"我不管你有什麼過去……我剛叫你什麼？<color=#ffd34c>露露</color>？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래. 루루로 하자.","JPN":"うん。ルルにしよ。","ENG":"Okay. Let’s go with Lulu.","TWN":"好！你就叫露露吧！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"마음에 안 들면 네가 다시 새로 짓던가 해. 내가 부르려고 대충 지은 거니까.","JPN":"気に入らなかったらアンタがつけ直しなよ。私が呼ぶために適当につけたから。","ENG":"If you don’t like it, you can make your own name. I'm just calling you whatever popped into my head at the time.","TWN":"不喜歡的話你再自己取一個吧，這只是方便我叫你時用的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"루루……?","JPN":"ルル……？","ENG":"Lulu...?","TWN":"露露……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루. 이제 와서 이쪽 잡고 있어. 고정시킬 벽돌이나 돌멩이 좀 가져오게.","JPN":"ルル。こっち来てこれ掴んでて。固定するレンガとか石とか持ってくるから。","ENG":"Lulu, come here and grab this. I’ll find a brick to hold it in place.","TWN":"露露，你先幫我抓著這裡，我去找石頭來。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"응. 알겠어, 글린다.","JPN":"うん。わかった、グリンダ。","ENG":"Okay, Glinda.","TWN":"嗯，好的，格琳達。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 정도면 하룻밤 정도는 보낼 수 있겠지?","JPN":"これなら一晩くらいは過ごせそうじゃない？","ENG":"This looks good enough to spend a night, right?","TWN":"這樣度過一晚應該沒問題吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L40_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"와…… 와아…….","JPN":"わ……わあ……","ENG":"W-whoa...","TWN":"哇……哇哇……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……뭘 그렇게까지 놀라고 그래?","JPN":"……何をそこまで驚くんだよ？","ENG":"What are you so surprised about?","TWN":"……有什麼好哇哇叫的啦？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"정말 대단해! 쓰레기로 이렇게 훌륭한 잠자리를 만들다니.","JPN":"本当にすごい！　ゴミでこんなに素晴らしい寝床を作るなんて。","ENG":"That’s amazing! You created a comfy bed out of trash!","TWN":"好厲害喔！竟然可以把垃圾變成這麼棒的床！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"거창하게 잠자리는 무슨. 큼, 크흠. 민망하게.","JPN":"寝床って大げさだし。ゴホン、コホン。恥ずかしいな。","ENG":"Comfy bed? Ahem...! Not that much.","TWN":"沒那麼誇張啦，什麼床，咳咳，聽你這樣說反而覺得很丟臉。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"이런 건 처음 봐.","JPN":"こんなの初めて見たよ。","ENG":"I’ve never seen anything like this before.","TWN":"真是大開眼界！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"음…… 칭찬은 맞는 거지?","JPN":"えっと……褒めてるんだよね？","ENG":"Hmm? That’s supposed to be a compliment, right?","TWN":"呃……你是在誇我沒錯吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"그럼, 그럼. 글린다는 재주가 좋구나?","JPN":"もちろん。グリンダは器用なんだね。","ENG":"Of course. You’re really talented, Glinda.","TWN":"當然囉，格琳達好有才華喔～"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……아무리 생각해도 놀리는 것 같은데?","JPN":"……どう考えてもからかってない？","ENG":"Now you’re just making fun of me.","TWN":"……怎麼感覺是在諷刺我？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"아니야. 진심이야. 이런 멋진 걸 만들 수 있는 사람이 몇 명이나 있겠어.","JPN":"違うよ。本気だよ。こんな素敵なものを作れる人はそんなに多くないもん。","ENG":"No, I’m telling you the truth. How many people do you know who can create something so nice?","TWN":"才不是，我是認真的。應該很少人能做出這麼棒的東西吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……적어도 위저드 애들은 다 만들 수 있을걸? 대부분이 가출 청소년 출신이니까.","JPN":"……少なくともウィザードの子たちはみんな作れると思うんだけど。ほとんどが家出してきたんだし。","ENG":"Well, maybe most of kids at Wizard can do. They’re mostly from the streets too.","TWN":"……魔法師的孩子們應該都做得出來吧？因為大家都是逃家的青少年。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"어쨌든 나는 처음 보니까. 멋있고, 대단해.","JPN":"とにかく私は初めて見たから。カッコいいし、すごい。","ENG":"Anyway, it’s the first for me. It looks nice and great.","TWN":"總之我是第一次見識到，覺得很酷，厲害！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……아부하는 거야, 뭐야.","JPN":"……お世辞なのかなんなのか。","ENG":"Are you trying to flatter me or what?","TWN":"……是在逗我開心嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"피곤해 죽겠네.","JPN":"めっちゃ疲れた。","ENG":"Oof, I’m exhausted.","TWN":"有夠累的，"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너도 누울 자리 정돈 만들어 뒀으니까 오든가 말든가 해.","JPN":"アンタも横になるくらいの空間は作っておいたから好きにして。","ENG":"I made enough room for both of us. If you want, you can lie down next to me.","TWN":"我也有弄一個你的位置，要不要睡就看你吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_HORN_FAKE","text":{"KOREA":"으응. 고마워.","JPN":"うん。ありがとう。","ENG":"Um... Thanks.","TWN":"嗯嗯，謝謝。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_HORN_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"흐아암. 졸려…….","JPN":"ふわぁ。眠い……","ENG":"*Yawn* I’m sleepy...","TWN":"呼哈～好睏……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"노숙은 오랜만인데, 괜찮으려나……","JPN":"野宿は久しぶりだけど、大丈夫かな……","ENG":"It’s been a long time since I’ve slept out on the streets...","TWN":"好久沒露宿街頭了，不會有什麼事吧……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"<color=#ffd34c>……zzZ</color>","JPN":"<color=#ffd34c>……zzZ</color>","ENG":"<color=#ffd34c>...zzZ</color>","TWN":"<color=#ffd34c>……zzZ</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};